import React from 'react';
import { StarRating } from './StarRating';

export default function App() {
  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Star Rating</h1>
      <div style={{ display: 'flex', flexDirection: 'column', gap: '1.5rem' }}>
        <div>
          <p style={{ marginBottom: '0.5rem', color: '#6b7280' }}>Rate this course:</p>
          <StarRating />
        </div>
        <div>
          <p style={{ marginBottom: '0.5rem', color: '#6b7280' }}>10-star scale:</p>
          <StarRating maxStars={10} />
        </div>
      </div>
    </div>
  );
}

import React from 'react';
import './styles.css';

interface StarRatingProps {
  /** Maximum number of stars */
  maxStars?: number;
  /** Called when the user selects a rating */
  onChange?: (rating: number) => void;
}

export const StarRating: React.FC<StarRatingProps> = ({
  maxStars = 5,
  onChange,
}) => {
  // TODO: Track selected rating

  return (
    <div className="star-rating" data-testid="star-rating">
      {Array.from({ length: maxStars }, (_, i) => (
        <button
          key={i}
          data-testid={`star-${i + 1}`}
          className="star-rating__star"
          aria-label={`Rate ${i + 1} out of ${maxStars}`}
        >
          &#9733;
        </button>
      ))}
      <span data-testid="rating-value" className="star-rating__value">
        0 / {maxStars}
      </span>
    </div>
  );
};

export default StarRating;

.star-rating {
  display: flex;
  align-items: center;
  gap: 0.25rem;
}

.star-rating__star {
  background: none;
  border: none;
  cursor: pointer;
  font-size: 1.75rem;
  color: #d1d5db;
  transition: color 0.15s ease, transform 0.1s ease;
  padding: 0.125rem;
  line-height: 1;
}

.star-rating__star:hover {
  transform: scale(1.15);
}

.star-rating__star--filled {
  color: #f59e0b;
}

.star-rating__value {
  margin-left: 0.75rem;
  font-size: 0.875rem;
  color: #6b7280;
  font-variant-numeric: tabular-nums;
}

