import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import { StarRating } from './StarRating';

describe('StarRating', () => {
  it('renders 5 stars by default', () => {
    render(<StarRating />);
    for (let i = 1; i <= 5; i++) {
      expect(screen.getByTestId(`star-${i}`)).toBeInTheDocument();
    }
  });

  it('shows 0 rating initially', () => {
    render(<StarRating />);
    expect(screen.getByTestId('rating-value')).toHaveTextContent('0 / 5');
  });

  it('selects rating when a star is clicked', () => {
    render(<StarRating />);
    fireEvent.click(screen.getByTestId('star-3'));
    expect(screen.getByTestId('rating-value')).toHaveTextContent('3 / 5');
  });

  it('fills stars up to the selected rating', () => {
    render(<StarRating />);
    fireEvent.click(screen.getByTestId('star-3'));
    expect(screen.getByTestId('star-1')).toHaveClass('star-rating__star--filled');
    expect(screen.getByTestId('star-2')).toHaveClass('star-rating__star--filled');
    expect(screen.getByTestId('star-3')).toHaveClass('star-rating__star--filled');
    expect(screen.getByTestId('star-4')).not.toHaveClass('star-rating__star--filled');
    expect(screen.getByTestId('star-5')).not.toHaveClass('star-rating__star--filled');
  });

  it('deselects when clicking the same star', () => {
    render(<StarRating />);
    fireEvent.click(screen.getByTestId('star-3'));
    fireEvent.click(screen.getByTestId('star-3'));
    expect(screen.getByTestId('rating-value')).toHaveTextContent('0 / 5');
  });

  it('calls onChange with the selected rating', () => {
    const spy = jest.fn();
    render(<StarRating onChange={spy} />);
    fireEvent.click(screen.getByTestId('star-4'));
    expect(spy).toHaveBeenCalledWith(4);
  });

  it('supports custom maxStars', () => {
    render(<StarRating maxStars={3} />);
    expect(screen.getByTestId('star-1')).toBeInTheDocument();
    expect(screen.getByTestId('star-2')).toBeInTheDocument();
    expect(screen.getByTestId('star-3')).toBeInTheDocument();
    expect(screen.queryByTestId('star-4')).not.toBeInTheDocument();
    expect(screen.getByTestId('rating-value')).toHaveTextContent('0 / 3');
  });
});

