import React, { useState } from 'react';
import './styles.css';

interface StarRatingProps {
  maxStars?: number;
  onChange?: (rating: number) => void;
}

export const StarRating: React.FC<StarRatingProps> = ({
  maxStars = 5,
  onChange,
}) => {
  const [rating, setRating] = useState(0);

  const handleClick = (value: number) => {
    const next = value === rating ? 0 : value;
    setRating(next);
    onChange?.(next);
  };

  return (
    <div className="star-rating" data-testid="star-rating">
      {Array.from({ length: maxStars }, (_, i) => {
        const value = i + 1;
        const filled = value <= rating;
        return (
          <button
            key={i}
            data-testid={`star-${value}`}
            className={`star-rating__star${filled ? ' star-rating__star--filled' : ''}`}
            aria-label={`Rate ${value} out of ${maxStars}`}
            onClick={() => handleClick(value)}
          >
            &#9733;
          </button>
        );
      })}
      <span data-testid="rating-value" className="star-rating__value">
        {rating} / {maxStars}
      </span>
    </div>
  );
};

export default StarRating;
